(function(P){
load=async function(){sourceFile=$('pdf').files[0];if(!sourceFile)throw Error('เลือกไฟล์โปรโมชั่นก่อน');const buf=await sourceFile.arrayBuffer(),sig=new TextDecoder().decode(new Uint8Array(buf.slice(0,5)));if(sig!=='%PDF-')throw Error('เนื้อไฟล์ไม่ใช่ PDF แม้นามสกุลไฟล์จะเป็น .pdf หรือ .png');pdf=await pdfjsLib.getDocument({data:buf}).promise;if(pdf.numPages<1||pdf.numPages>60)throw Error(`จำนวนหน้า ${pdf.numPages} ผิดปกติ`);return pdf};
stableGridBoxes=function(pg){
  const w=pg.width,h=pg.height,anchors=innerCardBoxes(pg),rows=rowGroups(anchors);if(!rows.length)throw Error('ไม่พบการ์ดสำหรับล็อกกริด');const hs=scoreAxis(pg,'y',w*.025,w*.975),hBands=scoreBands(hs,.56,h*.17,h,2),yb=[],firstY=Math.min(...rows[0].boxes.map(b=>b.y));let band=pickBand(hBands,Math.max(h*.17,firstY-25),firstY+25,firstY);yb.push(Math.round(band?band.start:Math.max(0,firstY-4)));
  for(let i=0;i<rows.length-1;i++){const py=median(rows[i].boxes.map(b=>b.y+b.h)),ny=median(rows[i+1].boxes.map(b=>b.y));band=pickBand(hBands,py-20,ny+60,(py+ny)/2);yb.push(Math.round(band?band.center:(py+ny)/2))}const ly=median(rows.at(-1).boxes.map(b=>b.y+b.h));band=pickBand(hBands,ly-10,h-1,ly+40);yb.push(Math.round(band?band.start:Math.min(h,ly+20)));for(let i=1;i<yb.length;i++)yb[i]=Math.max(yb[i],yb[i-1]+80);
  function gridCandidate(bands,n){if(bands.length<n+1)return null;const left=bands[0],right=bands.at(-1),step=(right.center-left.center)/n;if(step<=0)return null;const chosen=[],dev=[];for(let i=0;i<=n;i++){const ex=left.center+step*i,c=[...bands].sort((a,b)=>Math.abs(a.center-ex)-Math.abs(b.center-ex)).find(b=>chosen.every(q=>Math.abs(b.center-q.center)>10));if(!c||Math.abs(c.center-ex)>step*.22)return null;chosen.push(c);dev.push(Math.abs(c.center-ex)/step)}chosen.sort((a,b)=>a.center-b.center);const gaps=[];for(let i=1;i<chosen.length;i++)gaps.push(chosen[i].center-chosen[i-1].center);if(Math.max(...gaps)-Math.min(...gaps)>median(gaps)*.12)return null;return{layout:n,full:chosen.map(b=>Math.round(b.center)),score:dev.reduce((a,b)=>a+b,0)+Math.abs((right.center-left.center)/w-.928)}}
  const raw=[];for(let ri=0;ri<rows.length;ri++){const row=rows[ri],y0=yb[ri],y1=yb[ri+1],actual=row.boxes.length,medw=median(row.boxes.map(b=>b.w)),vs=scoreAxis(pg,'x',y0,y1),bands=scoreBands(vs,.55,w*.02,w*.99,2).filter(b=>b.max>.55),candidates=[];for(let n=Math.max(3,actual);n<=8;n++){const c=gridCandidate(bands,n);if(c)candidates.push(c)}let picked=candidates.sort((a,b)=>a.score-b.score||a.layout-b.layout)[0]||null;if(!picked){const layout=medw<w*.155?6:(medw<w*.19?5:4);picked={layout:Math.max(actual,layout),full:null}}raw.push({row,y0,y1,layout:picked.layout,full:picked.full})}
  const templates={};for(const n of[...new Set(raw.map(r=>r.layout))]){const arr=raw.filter(r=>r.layout===n&&r.full).map(r=>r.full);templates[n]=arr.length?Array.from({length:n+1},(_,i)=>Math.round(median(arr.map(a=>a[i])))):Array.from({length:n+1},(_,i)=>Math.round(w*.036+(w*.964-w*.036)*i/n))}
  const out=[];for(const r of raw){const t=templates[r.layout],full=r.full?r.full.map((x,i)=>Math.abs(x-t[i])<=8?Math.round((x+t[i])/2):t[i]):[...t],used=new Set();for(const a of r.row.boxes){const cx=a.x+a.w/2;let ci=-1;for(let i=0;i<r.layout;i++)if(cx>=full[i]&&cx<full[i+1]){ci=i;break}if(ci<0)ci=Math.max(0,Math.min(r.layout-1,Math.round((cx-full[0])/Math.max(1,full.at(-1)-full[0])*r.layout-.5)));if(used.has(ci))throw Error('กริดมีการ์ดซ้ำในช่องเดียว');used.add(ci);out.push({x:full[ci],y:r.y0,w:full[ci+1]-full[ci],h:r.y1-r.y0,gridLocked:true,rowLayout:r.layout,rowCell:ci+1})}}
  const ordered=rows.flatMap(r=>r.boxes);if(out.length!==ordered.length)throw Error(`จำนวนกรอบ ${out.length} ไม่ตรง anchor ${ordered.length}`);for(let i=0;i<out.length;i++){const r=out[i],a=ordered[i],cx=a.x+a.w/2,cy=a.y+a.h/2;if(!(cx>=r.x&&cx<r.x+r.w&&cy>=r.y&&cy<r.y+r.h))throw Error(`กริดใบ ${i+1} ไม่ครอบ anchor`);let inside=0;for(const q of ordered){const x=q.x+q.w/2,y=q.y+q.h/2;if(x>=r.x&&x<r.x+r.w&&y>=r.y&&y<r.y+r.h)inside++}if(inside!==1)throw Error(`กริดใบ ${i+1} มี anchor ${inside}`)}return out;
};
})(window.PromoDynamicV1||(window.PromoDynamicV1={}));
